package com.campkin.api;
import com.campkin.api.ApiModels.*; import com.campkin.domain.*; import com.campkin.repo.*; import com.campkin.service.*; import com.fasterxml.jackson.core.type.TypeReference; import com.fasterxml.jackson.databind.ObjectMapper; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile; import java.io.*; import java.time.*; import java.util.*;
@RestController @RequestMapping("/api") @RequiredArgsConstructor public class CampController {
 private final CampService service; private final ExcelImportService importer; private final LeaderImportService leaderImporter; private final AssignmentService assignments; private final PdfService pdf; private final PreferenceRepository preferences; private final CamperRepository campers; private final AccessService access; private final ObjectMapper objectMapper;
 @GetMapping("/health") Map<String,String> health(){return Map.of("status","ok");}
 @GetMapping("/camps") List<Camp> camps(){return service.list();} @PostMapping("/camps") @ResponseStatus(HttpStatus.CREATED) Camp create(@Valid @RequestBody CampRequest r){return service.create(r);}
 @DeleteMapping("/camps/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteCamp(@PathVariable UUID id){access.requireOwner(id);service.deleteCamp(id);}
 @GetMapping("/camps/{id}/dashboard") Dashboard dashboard(@PathVariable UUID id){access.requireCamp(id);return service.dashboard(id);} @GetMapping("/camps/{id}/campers/search") List<CamperView> search(@PathVariable UUID id,@RequestParam String q){access.requireCamp(id);return service.search(id,q);}
 @PostMapping("/camps/{id}/leaders") @ResponseStatus(HttpStatus.CREATED) Leader addLeader(@PathVariable UUID id,@Valid @RequestBody LeaderRequest r){access.requireCamp(id);return service.addLeader(id,r);}
 @PatchMapping("/leaders/{id}") Leader updateLeader(@PathVariable UUID id,@Valid @RequestBody LeaderRequest r){access.requireLeader(id);return service.updateLeader(id,r);}
 @DeleteMapping("/leaders/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteLeader(@PathVariable UUID id){access.requireLeader(id);service.deleteLeader(id);}
 @PostMapping(value="/camps/{id}/leaders/import",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) LeaderImportResult importLeaders(@PathVariable UUID id,@RequestPart MultipartFile file)throws IOException{access.requireCamp(id);return leaderImporter.importFile(id,file);}
 @PostMapping("/camps/{id}/rooms") @ResponseStatus(HttpStatus.CREATED) Room room(@PathVariable UUID id,@Valid @RequestBody RoomRequest r){access.requireCamp(id);return service.addRoom(id,r);}
 @PostMapping("/camps/{id}/rooms/batch") @ResponseStatus(HttpStatus.CREATED) List<Room> rooms(@PathVariable UUID id,@Valid @RequestBody BatchRoomRequest r){access.requireCamp(id);return service.addRooms(id,r);}
 @PatchMapping("/rooms/{id}") Room renameRoom(@PathVariable UUID id,@Valid @RequestBody RoomRenameRequest r){access.requireRoom(id);return service.renameRoom(id,r);}
 @PutMapping("/rooms/{id}/leaders") void updateRoomLeaders(@PathVariable UUID id,@Valid @RequestBody RoomLeadersUpdateRequest r){access.requireRoom(id);service.updateRoomLeaders(id,r);}
 @PutMapping("/groups/{id}/leaders") void updateGroupLeaders(@PathVariable UUID id,@Valid @RequestBody GroupLeadersUpdateRequest r){access.requireGroup(id);service.updateGroupLeaders(id,r);}
 @PostMapping("/camps/{id}/rooms/leaders/auto") void autoRoomLeaders(@PathVariable UUID id){access.requireCamp(id);service.autoAssignRoomLeaders(id);}
 @PostMapping("/camps/{id}/groups/leaders/auto") void autoGroupLeaders(@PathVariable UUID id,@Valid @RequestBody AutoGroupLeadersRequest r){access.requireCamp(id);service.autoAssignGroupLeaders(id,r);}
 @PatchMapping("/caring-groups/{id}/leader") void updateCaringLeader(@PathVariable UUID id,@Valid @RequestBody CaringLeaderUpdateRequest r){access.requireCaringGroup(id);service.updateCaringLeader(id,r);}
 @DeleteMapping("/rooms/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteRoom(@PathVariable UUID id){access.requireRoom(id);service.deleteRoom(id);}
 @PostMapping(value="/camps/{id}/import/preview",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) ImportPreview previewCampers(@PathVariable UUID id,@RequestPart MultipartFile file)throws IOException{access.requireCamp(id);return importer.previewFile(file);}
 @PostMapping(value="/camps/{id}/import",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) ImportResult importCampers(@PathVariable UUID id,@RequestPart MultipartFile file,@RequestParam(defaultValue="{}") String birthdates)throws IOException{access.requireCamp(id);Map<String,String> supplied=objectMapper.readValue(birthdates,new TypeReference<>(){});return importer.importFile(id,file,supplied);}
 @PostMapping("/camps/{id}/infer-genders") Map<String,Integer> inferGenders(@PathVariable UUID id){access.requireCamp(id);return Map.of("inferred",importer.inferGenders(id));}
 @PostMapping("/camps/{id}/assign/rooms") void assignRooms(@PathVariable UUID id,@Valid @RequestBody GenerateRoomsRequest r){access.requireCamp(id);assignments.assignRooms(id,r);} @PostMapping("/camps/{id}/assign/groups") void assignGroups(@PathVariable UUID id,@Valid @RequestBody GroupRequest r){access.requireCamp(id);assignments.assignGroups(id,r);}
 @PostMapping("/camps/{id}/assign/caring") void assignCaring(@PathVariable UUID id,@Valid @RequestBody GenerateCaringRequest r){access.requireCamp(id);assignments.assignCaring(id,r);}
 @PatchMapping("/campers/{id}/assignment") void move(@PathVariable UUID id,@RequestBody MoveRequest r){access.requireCamper(id);service.move(id,r);}
 @PatchMapping("/campers/{id}/gender") void gender(@PathVariable UUID id,@Valid @RequestBody GenderRequest r){access.requireCamper(id);service.updateGender(id,r);}
 @DeleteMapping("/campers/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteCamper(@PathVariable UUID id){access.requireCamper(id);service.deleteCamper(id);}
 @DeleteMapping("/campers") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteCampers(@Valid @RequestBody CamperIdsRequest request){request.camperIds().forEach(access::requireCamper);service.deleteCampers(request.camperIds());}
 @PatchMapping("/preferences/{id}/resolve") void resolve(@PathVariable UUID id,@Valid @RequestBody MatchRequest r){access.requirePreference(id);access.requireCamper(r.matchedCamperId());Preference p=preferences.findById(id).orElseThrow();Camper c=campers.findById(r.matchedCamperId()).orElseThrow();if(c.getCamp().getId().equals(p.getCamper().getCamp().getId())){p.setMatchedCamper(c);p.setStatus(Domain.PreferenceStatus.MATCHED);p.setSimilarity(1d);p.setAlternatives(null);}else throw new IllegalArgumentException("Camper belongs to another camp");}
 @GetMapping(value="/camps/{id}/exports/rooms.pdf",produces=MediaType.APPLICATION_PDF_VALUE) ResponseEntity<byte[]> roomPdf(@PathVariable UUID id){access.requireCamp(id);return download(pdf.rooms(id),"room-assignments.pdf");} @GetMapping(value="/camps/{id}/exports/groups.pdf",produces=MediaType.APPLICATION_PDF_VALUE) ResponseEntity<byte[]> groupPdf(@PathVariable UUID id){access.requireCamp(id);return download(pdf.groups(id),"discussion-groups.pdf");} @GetMapping(value="/camps/{id}/exports/caring.pdf",produces=MediaType.APPLICATION_PDF_VALUE) ResponseEntity<byte[]> caringPdf(@PathVariable UUID id){access.requireCamp(id);return download(pdf.caring(id),"caring-groups.pdf");}
 private ResponseEntity<byte[]> download(byte[] bytes,String name){return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\""+name+"\"").body(bytes);}
}
